<?php declare(strict_types=1);
namespace App\Streaming;
final class FfmpegCommandBuilder { public function build(array $channel,string $playlist,array $settings,bool $hasAudio,array $profile):string{$level=config('app.debug')?config('ffmpeg.developer_loglevel'):config('ffmpeg.production_loglevel');$fps=(int)$profile['fps'];$gop=$fps*(int)config('ffmpeg.keyframe_seconds');$audio=$hasAudio?'-map 0:v:0 -map 0:a?':'-f lavfi -i anullsrc=channel_layout=stereo:sample_rate='.config('ffmpeg.audio_sample_rate').' -map 0:v:0 -map 1:a:0 -shortest';return escapeshellarg($settings['ffmpeg_path']).' -hide_banner -loglevel '.escapeshellarg($level).' -re -stream_loop -1 -f concat -safe 0 -i '.escapeshellarg($playlist).' '.$audio.' -vf '.escapeshellarg('scale='.$profile['resolution']).' -c:v libx264 -pix_fmt yuv420p -preset '.escapeshellarg($profile['preset']).' -r '.$fps.' -g '.$gop.' -keyint_min '.$gop.' -sc_threshold 0 -b:v '.escapeshellarg($profile['bitrate']).' -c:a aac -ar '.config('ffmpeg.audio_sample_rate').' -b:a '.escapeshellarg(config('ffmpeg.audio_bitrate')).' -f flv '.escapeshellarg($channel['rtmp_url'].'/'.$channel['stream_key']);} public function settings(array $profile):array{return ['resolution'=>$profile['resolution'],'fps'=>$profile['fps'],'preset'=>$profile['preset'],'bitrate'=>$profile['bitrate'],'gop'=>(int)$profile['fps']*(int)config('ffmpeg.keyframe_seconds')];} }
